  ?season wdt:P31 wd:Q1985827 ;
          wdt:P3450 wd:Q9673 ;
          wdt:P1580 ?races ;
          wdt:P585 ?date .
  BIND(YEAR(?date) AS ?year)
  FILTER(?year >= 2015)
}
ORDER BY DESC(?races)

